import{_ as a,o as e,c as l,ag as i}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"豆瓣求片","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/douban-requests.md","filePath":"guide/help/douban-requests.md","lastUpdated":1780491682000}'),d={name:"guide/help/douban-requests.md"};function r(o,t,h,n,p,b){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="豆瓣求片" tabindex="-1">豆瓣求片 <a class="header-anchor" href="#豆瓣求片" aria-label="Permalink to &quot;豆瓣求片&quot;">​</a></h1><p>豆瓣求片用于把用户的豆瓣片单变成 PanSave 可处理的求片任务。适合家人、朋友或多个用户用各自片单表达“想看什么”，系统负责同步、查库、搜索、转存和通知。</p><p>入口：<code>资源获取 / 豆瓣求片</code></p><h2 id="使用前准备" tabindex="-1">使用前准备 <a class="header-anchor" href="#使用前准备" aria-label="Permalink to &quot;使用前准备&quot;">​</a></h2><p>豆瓣求片需要先完成：</p><ul><li>Emby 配置</li><li>TMDB 配置</li><li>监控策略里的搜索来源</li><li>搜索来源对应的网盘转存目标</li></ul><p>豆瓣求片不会单独维护搜索频道。它继承当前 Emby 服务器在监控策略中启用的搜索来源。</p><h2 id="添加求片用户" tabindex="-1">添加求片用户 <a class="header-anchor" href="#添加求片用户" aria-label="Permalink to &quot;添加求片用户&quot;">​</a></h2><p>每个求片用户至少需要：</p><ul><li>用户名：系统里用于区分用户，不一定等于豆瓣真实昵称。</li><li>豆瓣片单 ID：片单地址里的编号。</li><li>通知邮箱：可选，开启用户级通知时必填。</li></ul><p>同一个 Emby 服务器下，求片用户名称不能重复。每个 Emby 服务器最多允许 10 个求片用户。</p><h2 id="测试抓取" tabindex="-1">测试抓取 <a class="header-anchor" href="#测试抓取" aria-label="Permalink to &quot;测试抓取&quot;">​</a></h2><p>保存前建议先点“测试抓取”。</p><p>测试抓取用于确认：</p><ul><li>片单 ID 是否正确</li><li>片单是否能访问</li><li>系统能否识别电影或剧集</li><li>同步预览是否符合预期</li></ul><p>如果片单需要登录才能稳定读取，可以在页面里按短信验证码流程保存豆瓣登录状态。未登录时，系统仍会尝试读取公开可访问的片单。</p><h2 id="开启同步" tabindex="-1">开启同步 <a class="header-anchor" href="#开启同步" aria-label="Permalink to &quot;开启同步&quot;">​</a></h2><p>开启总开关后，系统会按固定频率同步片单。</p><p>新条目进入后，系统会先检查 Emby：</p><table tabindex="0"><thead><tr><th>检查结果</th><th>后续行为</th></tr></thead><tbody><tr><td>已完整入库</td><td>标记为已入库，不再搜索。</td></tr><tr><td>已入库但缺集</td><td>标记为缺集，并交给监控清单继续跟踪。</td></tr><tr><td>未入库</td><td>按监控策略里的来源搜索并尝试转存。</td></tr></tbody></table><h2 id="状态怎么理解" tabindex="-1">状态怎么理解 <a class="header-anchor" href="#状态怎么理解" aria-label="Permalink to &quot;状态怎么理解&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>待检测</td><td>新同步进来的条目，等待检查和处理。</td></tr><tr><td>已转存</td><td>已经发起转存，等待后续 Emby 确认是否入库。</td></tr><tr><td>已入库</td><td>Emby 已确认完整存在。</td></tr><tr><td>已入库但缺集</td><td>Emby 有这个剧集，但仍缺少部分集数。</td></tr><tr><td>监控中</td><td>暂时没找到或还没补齐，后续交给监控清单继续跟踪。</td></tr></tbody></table><p>如果某个条目已经进入“已转存”但 6 小时后仍未在 Emby 里确认，系统会重新把它放回待处理流程。</p><h2 id="什么时候会重新搜索" tabindex="-1">什么时候会重新搜索 <a class="header-anchor" href="#什么时候会重新搜索" aria-label="Permalink to &quot;什么时候会重新搜索&quot;">​</a></h2><p>豆瓣求片不是每轮都无脑重搜。只有在搜索依据变化时才会重新处理，例如：</p><ul><li>新同步进来的片单条目</li><li>TMDB 匹配结果变化</li><li>原来已入库的资源后来在 Emby 里消失</li><li>监控策略新增了可搜索来源</li><li>总开关从关闭重新开启</li></ul><p>这样能减少重复请求和重复转存。</p><h2 id="通知" tabindex="-1">通知 <a class="header-anchor" href="#通知" aria-label="Permalink to &quot;通知&quot;">​</a></h2><p>豆瓣求片会按状态变化聚合通知：</p><ul><li>管理员可以收到系统级摘要</li><li>求片用户可以收到和自己片单相关的邮件</li></ul><p>邮件需要先在 <code>系统配置 / 邮箱配置</code> 中启用。Telegram 系统提醒由内置机器人负责。</p><h2 id="排查建议" tabindex="-1">排查建议 <a class="header-anchor" href="#排查建议" aria-label="Permalink to &quot;排查建议&quot;">​</a></h2><p>如果豆瓣求片没有按预期处理：</p><ol><li>确认当前 Emby 已选对。</li><li>确认监控策略里有启用搜索来源。</li><li>确认来源已经关联网盘，并且网盘有整理源目录。</li><li>确认 TMDB 和 Emby 测试通过。</li><li>查看系统日志和该条目的处理历史。</li></ol>',34)])])}const c=a(d,[["render",r]]);export{u as __pageData,c as default};
